{% extends "_base/base.html.j2" %}

{% block letterhead %}{% endblock %}
{% block letterhead_small_sender %}{% endblock %}


{% block title %}{{ L.pallet }} {{ data.sscc }}{% endblock %}

{% block content %}

  {# Header — Adress-Block links (Shipper), rechts Consignee. #}
  <section class="pl-addresses" aria-label="Addresses">
    <div class="pl-addr">
      <div class="pl-addr__label">{{ L.shipper }}</div>
      <div class="pl-addr__body">
        <strong>{{ data.shipper.name }}</strong><br>
        {{ data.shipper.address }}
      </div>
    </div>
    <div class="pl-addr">
      <div class="pl-addr__label">{{ L.consignee }}</div>
      <div class="pl-addr__body pl-addr__body--big">
        <strong>{{ data.consignee.name }}</strong><br>
        {{ data.consignee.address }}
      </div>
    </div>
  </section>

  {# Meta-Tile — Lieferschein-Nr, Auftrag, Gewicht, Anzahl, Charge, MHD. #}
  <section class="pl-meta">
    <dl class="pl-meta__dl">
      {% if data.deliveryNoteNumber %}<div><dt>{{ L.delivery_note }}</dt><dd>{{ data.deliveryNoteNumber }}</dd></div>{% endif %}
      {% if data.orderNumber %}<div><dt>{{ L.order }}</dt><dd>{{ data.orderNumber }}</dd></div>{% endif %}
      {% if data.palletNumber %}<div><dt>{{ L.pallet }}</dt><dd>{{ data.palletNumber }}</dd></div>{% endif %}
      {% if data.itemCount %}<div><dt>{{ L.item_count }}</dt><dd>{{ data.itemCount }}</dd></div>{% endif %}
      {% if data.grossWeight %}<div><dt>{{ L.gross_weight }}</dt><dd>{{ data.grossWeight }}</dd></div>{% endif %}
      {% if data.netWeight %}<div><dt>{{ L.net_weight }}</dt><dd>{{ data.netWeight }}</dd></div>{% endif %}
      {% if data.lotNumber %}<div><dt>{{ L.lot }}</dt><dd>{{ data.lotNumber }}</dd></div>{% endif %}
      {% if data.bestBefore %}<div><dt>{{ L.best_before }}</dt><dd>{{ data.bestBefore }}</dd></div>{% endif %}
      {% if data.productionDate %}<div><dt>{{ L.production_date }}</dt><dd>{{ data.productionDate }}</dd></div>{% endif %}
    </dl>
  </section>

  {# Inhalts-Mini-Tabelle (max. 5 Artikel — bei mehr fällt's auf eine Liste zurück). #}
  {% if data.contents %}
  <section class="pl-contents" aria-labelledby="pl-contents-heading">
    <h2 id="pl-contents-heading" class="pl-section-title">{{ L.contents }}</h2>
    <table class="pl-contents__table">
      <thead>
        <tr>
          <th>{{ L.col_sku }}</th>
          <th>{{ L.col_name }}</th>
          <th>{{ L.col_qty }}</th>
        </tr>
      </thead>
      <tbody>
        {% for it in data.contents[:6] %}
        <tr>
          <td class="pl-mono">{{ it.number }}</td>
          <td>{{ it.name }}</td>
          <td class="pl-qty">{{ it.quantity | number }} {{ it.unit | default('') }}</td>
        </tr>
        {% endfor %}
      </tbody>
    </table>
  </section>
  {% endif %}

  {# GS1-128 Mitte — Charge + MHD (AI 10 · 15). Optional. #}
  {% if data.lotNumber or data.bestBefore %}
  <section class="pl-gs1" aria-label="{{ L.gs1_label }}">
    <div class="pl-gs1__label">{{ L.gs1_label }}</div>
    <div class="barcode-gs1"></div>
    <div class="pl-gs1__caption">
      {% if data.lotNumber %}(10) {{ data.lotNumber }}{% endif %}
      {% if data.bestBefore %}{% if data.lotNumber %} &nbsp; {% endif %}(15) {{ data.bestBefore | replace('-', '') }}{% endif %}
    </div>
  </section>
  {% endif %}

  {# SSCC unten — das Hauptidentifikations-Element. Groß, gut scanbar. #}
  <section class="pl-sscc" aria-label="{{ L.sscc_label }} {{ data.sscc }}">
    <div class="pl-sscc__label">{{ L.sscc_label }} (00)</div>
    <div class="barcode-sscc"></div>
    <div class="pl-sscc__caption">{{ data.sscc }}</div>
  </section>

{% endblock %}

css:
/* Paletten-Label — A5, typischerweise 148×210mm hochkant. GS1
   Logistic-Label-Style: Adressblock oben, Meta-DL, optional Contents,
   GS1-128 Mitte (Charge+MHD), SSCC unten als Hauptcode. */

@page {
  size: A5;
  margin: 6mm;
}

body {
  margin: 0;
  padding: 0;
  font-size: 9pt;
  line-height: 1.3;
  color: #111827;
}

.box-letterhead,
.box-letterhead-small-sender {
  display: none !important;
}

.pl-addresses {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4mm;
  border-bottom: 0.3mm solid #111827;
  padding-bottom: 3mm;
  margin-bottom: 3mm;
}
.pl-addr__label {
  font-size: 7.5pt;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  color: #6b7280;
}
.pl-addr__body {
  font-size: 9pt;
  line-height: 1.35;
}
.pl-addr__body--big {
  font-size: 11pt;
  font-weight: 600;
  line-height: 1.3;
}

.pl-meta__dl {
  display: grid;
  grid-template-columns: repeat(2, max-content 1fr);
  gap: 0.5mm 3mm;
  margin: 0 0 3mm;
  font-size: 9pt;
}
.pl-meta__dl > div { display: contents; }
.pl-meta__dl dt {
  font-size: 7.5pt;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  color: #6b7280;
}
.pl-meta__dl dd {
  margin: 0;
  font-weight: 600;
  font-variant-numeric: tabular-nums;
}

.pl-section-title {
  font-size: 7.5pt;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  color: #6b7280;
  margin: 2mm 0 1mm;
}

.pl-contents__table {
  width: 100%;
  border-collapse: collapse;
  font-size: 8.5pt;
}
.pl-contents__table thead th {
  font-size: 7pt;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  text-align: left;
  padding: 1mm 2mm;
  color: #6b7280;
  border-bottom: 0.3mm solid #6b7280;
}
.pl-contents__table tbody td {
  padding: 1mm 2mm;
  border-bottom: 0.15mm solid #e5e7eb;
}
.pl-mono {
  font-family: monospace;
  font-size: 8pt;
  letter-spacing: 0.2pt;
}
.pl-qty {
  text-align: right;
  font-variant-numeric: tabular-nums;
}

.pl-gs1 {
  margin: 3mm 0;
  padding: 2mm 0;
  border-top: 0.2mm solid #d1d5db;
  border-bottom: 0.2mm solid #d1d5db;
}
.pl-gs1__label,
.pl-sscc__label {
  font-size: 7.5pt;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.4px;
  color: #6b7280;
  margin-bottom: 1mm;
}
.pl-gs1__caption {
  font-family: monospace;
  font-size: 9pt;
  margin-top: 1mm;
  letter-spacing: 0.3pt;
}

/* GS1-128 — dichteres Streifenmuster als EAN, mehr Variation. */
.barcode-gs1 {
  height: 12mm;
  background:
    repeating-linear-gradient(
      to right,
      #111827 0 0.4mm,
      transparent 0.4mm 0.8mm,
      #111827 0.8mm 1.2mm,
      transparent 1.2mm 1.6mm,
      #111827 1.6mm 1.8mm,
      transparent 1.8mm 2.6mm,
      #111827 2.6mm 3.0mm,
      transparent 3.0mm 3.4mm
    );
}

/* SSCC — Hauptidentifikator, dick und vorne mittig. Echte SSCC sind
   18-stellig, daher der Balken bewusst breit + groß zum Scannen. */
.pl-sscc {
  margin-top: 3mm;
  padding-top: 3mm;
  border-top: 0.4mm solid #111827;
}
.barcode-sscc {
  height: 24mm;
  background:
    repeating-linear-gradient(
      to right,
      #111827 0 0.6mm,
      transparent 0.6mm 1.2mm,
      #111827 1.2mm 1.5mm,
      transparent 1.5mm 2.2mm,
      #111827 2.2mm 2.6mm,
      transparent 2.6mm 3.4mm,
      #111827 3.4mm 3.8mm,
      transparent 3.8mm 4.4mm
    );
}
.pl-sscc__caption {
  font-family: monospace;
  font-size: 13pt;
  font-weight: 700;
  text-align: center;
  margin-top: 2mm;
  letter-spacing: 1pt;
}
